];

// --- Attributes (register once) -------------------------------------------

$attr_taxonomies = ['pa_brand', 'pa_color', 'pa_material', 'pa_storage'];
foreach ($attr_taxonomies as $tax) {
    $attr_name = str_replace('pa_', '', $tax);
    if (! taxonomy_exists($tax)) {
        wc_create_attribute(['name' => ucfirst($attr_name), 'slug' => $attr_name, 'type' => 'select']);
        register_taxonomy($tax, 'product');
    }
}

// --- Create products ------------------------------------------------------

$created = 0;
$skipped = 0;

foreach ($products as [$title, $subcategory, $price, $description, $attributes]) {
    // Check if product already exists
    $existing = get_posts([
        'post_type' => 'product',
        'title' => $title,
        'fields' => 'ids',
        'numberposts' => 1,
    ]);

    if (! empty($existing)) {
        $skipped++;

        continue;
    }

    $post_id = wp_insert_post([
        'post_title' => $title,
        'post_content' => $description,
        'post_status' => 'publish',
        'post_type' => 'product',
    ]);

    if (is_wp_error($post_id)) {
        WP_CLI::warning("Failed to create: {$title}");

        continue;
    }

    // WooCommerce meta
    update_post_meta($post_id, '_regular_price', $price);
    update_post_meta($post_id, '_price', $price);
    update_post_meta($post_id, '_stock_status', 'instock');
    update_post_meta($post_id, '_manage_stock', 'no');
    update_post_meta($post_id, '_visibility', 'visible');
    update_post_meta($post_id, '_sku', 'SEED-' . $post_id);

    // Some products on sale
    if (rand(1, 5) === 1) {
        $sale_price = round($price * (rand(70, 90) / 100), 2);
        update_post_meta($post_id, '_sale_price', $sale_price);
        update_post_meta($post_id, '_price', $sale_price);
    }

    // Rating
    $rating = round(rand(35, 50) / 10, 1);
    $rating_count = rand(5, 500);
    update_post_meta($post_id, '_wc_average_rating', $rating);
    update_post_meta($post_id, '_wc_review_count', $rating_count);
    update_post_meta($post_id, '_wc_rating_count', serialize([$rating => $rating_count]));

    // Categories
    $cat_ids = [];
    if (isset($category_ids[$subcategory])) {
        $cat_ids[] = $category_ids[$subcategory];
    }
    // Also add parent category
    foreach ($categories as $parent => $children) {
        if (\in_array($subcategory, $children, true) && isset($category_ids[$parent])) {
            $cat_ids[] = $category_ids[$parent];
            break;
        }
    }
    if (! empty($cat_ids)) {
        wp_set_object_terms($post_id, $cat_ids, 'product_cat');
    }

    // Product type
    wp_set_object_terms($post_id, 'simple', 'product_type');

    // Attributes
    $product_attributes = [];
    foreach ($attributes as $attr_name => $attr_value) {
        $taxonomy = 'pa_' . $attr_name;
        if (taxonomy_exists($taxonomy)) {
            wp_set_object_terms($post_id, $attr_value, $taxonomy, true);
            $product_attributes[$taxonomy] = [
                'name' => $taxonomy,
                'value' => '',
                'is_visible' => 1,
                'is_variation' => 0,
                'is_taxonomy' => 1,
            ];
        }
    }
    if (! empty($product_attributes)) {
        update_post_meta($post_id, '_product_attributes', $product_attributes);
    }

    $created++;
}

WP_CLI::success("Done! Created: {$created}, Skipped (existing): {$skipped}");
WP_CLI::log('Total products: ' . wp_count_posts('product')->publish);
